export type Lang = 'zh-hans' | 'zh-hant' | 'en' | 'ja';

export interface TranslationDict {
	[key: string]: string | TranslationDict;
}

export interface I18nConfig {
	defaultLang: Lang;
	supportedLangs: Lang[];
	langNames: Record<Lang, string>;
	langDisplayNames: Record<Lang, string>;
}

export const i18nConfig: I18nConfig = {
	defaultLang: 'zh-hans',
	supportedLangs: ['zh-hans', 'zh-hant', 'en', 'ja'],
	langNames: {
		'zh-hans': 'zh-CN',
		'zh-hant': 'zh-TW',
		en: 'en',
		ja: 'ja'
	},
	langDisplayNames: {
		'zh-hans': '简体字',
		'zh-hant': '正體字',
		en: 'English',
		ja: '日本語'
	}
};

export function isValidLang(lang: string): lang is Lang {
	return i18nConfig.supportedLangs.includes(lang as Lang);
}

export function getLangFromPath(pathname: string): Lang {
	const match = pathname.match(/^\/(zh-hans|zh-hant|en|ja)(?:\/|$)/);
	return match && isValidLang(match[1]) ? match[1] : i18nConfig.defaultLang;
}